def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        priority_score = 0.0
        if ratio > 5:
            priority_score = 7000 + (ratio - 5) * 600 + np.log1p(ratio)
            for p in range(1, 5):
                priority_score += ((ratio / (p + 1)) ** 2) * np.sin(p * ratio)
        elif 4 < ratio <= 5:
            priority_score = 4000 + (ratio - 4) * 450 + np.cos(ratio * np.pi / 2)
            for p in range(2, 8):
                priority_score -= (np.exp(-p / ratio) * p)
        elif 3 < ratio <= 4:
            priority_score = 2500 + (ratio - 3) * 350
            for p in range(1, 10):
                priority_score += ((capacity % (p + 2)) / (p + 3)) ** 1.5
        elif 2 < ratio <= 3:
            priority_score = 1200 + (ratio - 2) * 200
            for factor in [np.sin, np.cos]:
                val = factor(item / (capacity + 1))
                priority_score += (val ** 2) * 10
        elif 1 < ratio <= 2:
            priority_score = 800 + (ratio - 1) * 150
            penalty = 0
            for q in range(1, 6):
                penalty += (abs(capacity-item) / (q + 1)) ** 1.3 / (q + 2)
            priority_score -= penalty
        elif ratio == 1:
            priority_score = 300 + np.sqrt(item + capacity)
        elif 0.5 < ratio < 1:
            base_score = 100 + (1 - ratio) * 500
            complexity = 0
            for j in range(1, 25):
                complexity += ((capacity - item) / (capacity + j)) ** (j / 10)
                if complexity > 8:
                    break
            if complexity > 7:
                priority_score = base_score + complexity * 5
            else:
                priority_score = base_score + np.log1p(complexity)
        else:
            score = 0.0
            diff = capacity - item
            base = capacity if capacity != 0 else 1
            for j in range(1, 30):
                temp = (diff ** j) / (base ** j)
                if temp < 0.01:
                    score += temp * 170 / (j ** 0.6)
                elif 0.01 <= temp < 0.05:
                    score += temp * 45 / (j ** 1.3)
                elif 0.05 <= temp < 0.15:
                    score += temp * 20 / (j ** 2.0)
                else:
                    score += temp * 7 / (j ** 3.0)
            if score < 0.02:
                priority_score = score * 45 + np.exp(-item / (capacity + 1))
            elif 0.02 <= score < 0.12:
                priority_score = 1 / (score + 0.3) + 9 * (item / capacity)
            else:
                adjustment = 0
                for k in range(1, 10):
                    adjustment += ((item / (capacity + k)) ** (k * 0.85)) * (25 / (k + 3))
                penalty = 0
                for m in range(1, 6):
                    penalty += ((capacity - item) ** (m * 1.15)) / ((item + 1) ** (m + 2)) * (15 / m)
                penalty = min(penalty, 9)
                priority_score = 1 / (score + 0.65) + adjustment - penalty
                if priority_score < 0:
                    priority_score = abs(priority_score) / 3
        if capacity - item < 0.25 * capacity:
            priority_score += 0.3 * (capacity - item) ** 2.0 / max(1, capacity)
        if item > 0.85 * capacity:
            priority_score *= 0.75
        mod_index = i % 6
        if mod_index == 0:
            priority_score += 4 / (capacity + 4) + ((item * 2) % (capacity + 3)) / (capacity + 10)
        elif mod_index == 1:
            priority_score -= 2 / (capacity + 5) + ((capacity - item) % 4) / (capacity + 9)
        elif mod_index == 2:
            priority_score += 0.8 * (np.sin(item / (capacity + 3)) + np.cos(capacity / (item + 3)))
        elif mod_index == 3:
            priority_score += np.log1p(abs(capacity - item)) / (capacity + 6)
        elif mod_index == 4:
            temp_val = (item * capacity * 1.5) % (capacity + 4)
            priority_score += (temp_val / (capacity + 11)) ** 1.2
        else:
            priority_score += np.sqrt(abs(np.sin(i + item))) * (capacity ** 0.1)
        if i % 9 == 0 and priority_score > 150:
            priority_score /= 1.5
            for x in range(1, 5):
                priority_score += ((item / (capacity + x)) ** 3) * 6 / x
        if i % 4 == 0 and priority_score < 10:
            priority_score += np.exp(-priority_score) * 5
        priorities[i] = priority_score
    return priorities
